import * as React from 'react';
import ListCheckBoldOutlined from '@universe-design/icons-react/ListCheckBoldOutlined';
import type { RcMenuItemProps } from './internal-menu';
import { RcMenuItem } from './internal-menu';
import type { RenderIconInfo } from './internal-menu/interface';
import clsx from 'clsx';
import stylex from '@universe-design/stylex';
import { cssTypographyBody0 } from '../stylex';
import { MenuContext } from './MenuContext';
import type { TooltipProps } from '../tooltip';
import { Tooltip } from '../tooltip';
import { toFlatArray } from '../util';
import { HorizontalMenuInk } from './HorizontalMenuInk';
import { MenuTitle } from './MenuTitle';
import { EmptyElement } from '../shared/components/FirstLineAlign';

import './style';
/**
 * @docgen
 * @public
 */
export interface MenuItemProps extends Omit<RcMenuItemProps, 'title'> {
  /**
   * 菜单图标
   */
  icon?: React.ReactNode;
  /**
   * 是否对文本做溢出收起
   */
  textOverflow?: boolean;
  /**
   * 设置收缩时展示的悬浮标题
   */
  title?: React.ReactNode;
}

const MenuItemSuffixIcon = ({ isSelected }: RenderIconInfo) => {
  const { prefixCls, mode: rootMode, inlineCollapsed, showCheckmark, selectable } = React.useContext(MenuContext);
  return selectable && showCheckmark && rootMode === 'normal' && !inlineCollapsed ? (
    <>
      {/* 用于占位，在右侧留出空白 */}
      <span className={stylex(stylex.create({ width: 20, flexShrink: 0 }))} />
      {isSelected && <ListCheckBoldOutlined className={`${prefixCls}-item-suffix-icon`} />}
    </>
  ) : null;
};

const MenuItem = (props: MenuItemProps) => {
  const { className, children, title, icon, textOverflow: textOverflowInProps, disabled, ...rest } = props;
  const { prefixCls, inlineCollapsed, textOverflow, firstLevel, mode: rootMode } = React.useContext(MenuContext);
  let tooltipTitle = title;
  if (typeof title === 'undefined') {
    tooltipTitle = firstLevel ? children : '';
  } else if (title === false) {
    tooltipTitle = '';
  }
  const tooltipProps: TooltipProps = {
    title: tooltipTitle,
  };

  if (!inlineCollapsed) {
    // tooltipProps.title = null; // 这个属性变化会导致 children remount，从而引起 children transition 动画失效
    // Reset `visible` to fix control mode tooltip display not correct
    tooltipProps.visible = false;
  }
  const childrenLength = toFlatArray(children).length;

  const cls = clsx(
    className,
    `${prefixCls}-item--root-${rootMode}`,
    {
      [`${prefixCls}-item-only-child`]: (icon ? childrenLength + 1 : childrenLength) === 1,
    },
    stylex(rootMode === 'normal' && cssTypographyBody0),
  );

  const renderItemChildren = () => {
    const collapsedItem = inlineCollapsed && firstLevel;
    // 收起模式下显示 icon 或是 children 的第一个字符
    if (collapsedItem) {
      if (!icon && typeof children === 'string') {
        return <div className={`${prefixCls}-inline-collapsed-noicon`}>{children.charAt(0)}</div>;
      }
    }
    const showEllipsis = !collapsedItem && (textOverflowInProps ?? textOverflow);
    return (
      <MenuTitle
        style={collapsedItem ? { width: 0, overflow: 'hidden' } : {}}
        showEllipsis={showEllipsis}
        title={children}
      />
    );
  };

  const renderIcon = () =>
    icon && <div className={clsx(`${prefixCls}-icon-wrap`, disabled && `${prefixCls}-icon-wrap-disabled`)}>{icon}</div>;

  return (
    <Tooltip {...tooltipProps} overlayClassName={`${prefixCls}-inline-collapsed-tooltip`} placement="right">
      <RcMenuItem
        {...rest}
        className={cls}
        title={typeof title === 'string' ? title : undefined}
        itemIcon={MenuItemSuffixIcon}
        disabled={disabled}
      >
        {renderIcon()}
        {renderItemChildren()}
        {/* 保证在 children 为空的时候也能撑起 22px 高度 */}
        <EmptyElement />
        <HorizontalMenuInk />
      </RcMenuItem>
    </Tooltip>
  );
};
if (__DEV__) {
  MenuItem.displayName = 'MenuItem';
}

export default MenuItem;
